import{_ as d,o as e,c as o,ag as c}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Git Shell 别名：日常 Git 命令的快捷方式 | Dotfiles (ZH)","titleTemplate":":title","description":"Dotfiles 的 Git shell 别名。超过 80 个简写命令，加速提交、分支、差异、远程和子模块工作流。","frontmatter":{"title":"Git Shell 别名：日常 Git 命令的快捷方式","description":"Dotfiles 的 Git shell 别名。超过 80 个简写命令，加速提交、分支、差异、远程和子模块工作流。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Git Shell 别名：日常 Git 命令的快捷方式 preview","canonical":"/zh/aliases/git/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Git Shell 别名：日常 Git 命令的快捷方式","pageType":"docs","schemaType":"WebPage","metaTitle":"Git Shell 别名 - Dotfiles (CN)","permalink":"/zh/aliases/git/","sidebar":true,"meta":[{"name":"keywords","content":"git shell 别名, git 快捷方式, git dotfiles, git 提交别名, git 分支别名, git 推送别名, shell, bash, zsh, linux, macos"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Dotfiles 的 Git shell 别名。超过 80 个简写命令，加速提交、分支、差异、远程和子模块工作流。"},{"name":"twitter:title","content":"Git Shell 别名 - Dotfiles (CN)"},{"name":"og:title","content":"Git Shell 别名 - Dotfiles (CN)"},{"name":"og:description","content":"Dotfiles 的 Git shell 别名。超过 80 个简写命令，加速提交、分支、差异、远程和子模块工作流。"},{"name":"og:image:alt","content":"Dotfiles - 为你的 Shell 生活精心设计"},{"name":"og:locale","content":"zh_CN"}]},"headers":[],"relativePath":"zh/aliases/git/index.md","filePath":"zh/aliases/git/index.md","lastUpdated":1773010926000}'),r={name:"zh/aliases/git/index.md"};function a(i,t,g,l,h,s){return e(),o("div",null,[...t[0]||(t[0]=[c('<h1 id="git-shell-别名" tabindex="-1">Git Shell 别名 <a class="header-anchor" href="#git-shell-别名" aria-label="Permalink to &quot;Git Shell 别名&quot;">​</a></h1><p>Git shell 别名为常用 Git 命令创建快捷方式。属于 <a href="https://github.com/sebastienrousseau/dotfiles" target="_blank" rel="noreferrer">Dotfiles</a> 配置的一部分，由 Chezmoi 自动加载。</p><p>这些别名定义在 <code>git.aliases.sh</code> 和 <code>signing.aliases.sh</code> 中，安装后在任何 Bash 或 Zsh 会话中可用。</p><h2 id="核心" tabindex="-1">核心 <a class="header-anchor" href="#核心" aria-label="Permalink to &quot;核心&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>g</code></td><td><code>git</code></td><td>git 的简写</td></tr><tr><td><code>gtp</code></td><td><code>git rev-parse --show-toplevel</code></td><td>输出仓库的顶层目录</td></tr><tr><td><code>grpa</code></td><td><code>git rev-parse --abbrev-ref HEAD</code></td><td>输出当前分支名称</td></tr><tr><td><code>gconfl</code></td><td><code>git config --list</code></td><td>列出所有 Git 配置设置</td></tr><tr><td><code>gconfr</code></td><td><code>git config --local --get remote.origin.url</code></td><td>输出远程 origin URL</td></tr><tr><td><code>gconfdiff</code></td><td><code>git config alias.dcolor &quot;diff --color-words&quot;</code></td><td>配置按词着色的差异别名</td></tr></tbody></table><h2 id="工作区" tabindex="-1">工作区 <a class="header-anchor" href="#工作区" aria-label="Permalink to &quot;工作区&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>ga</code></td><td><code>git add</code></td><td>暂存文件</td></tr><tr><td><code>gaa</code></td><td><code>git add --all</code></td><td>暂存所有更改（已跟踪和未跟踪）</td></tr><tr><td><code>gad</code></td><td><code>git add .</code></td><td>暂存当前目录中的所有内容</td></tr><tr><td><code>gau</code></td><td><code>git add --update</code></td><td>暂存修改和删除（不包括新文件）</td></tr><tr><td><code>gcl</code></td><td><code>git clone</code></td><td>克隆仓库</td></tr><tr><td><code>gin</code></td><td><code>git init</code></td><td>初始化新的 Git 仓库</td></tr><tr><td><code>gco</code></td><td><code>git checkout</code></td><td>切换分支或恢复工作树文件</td></tr><tr><td><code>gcb</code></td><td><code>git checkout -b</code></td><td>创建并切换到新分支</td></tr><tr><td><code>gdis</code></td><td><code>git checkout --</code></td><td>丢弃工作目录中的更改</td></tr><tr><td><code>grs</code></td><td><code>git restore</code></td><td>恢复工作树文件</td></tr><tr><td><code>gmv</code></td><td><code>git mv</code></td><td>移动或重命名文件</td></tr><tr><td><code>grm</code></td><td><code>git rm</code></td><td>从工作树和索引中删除文件</td></tr><tr><td><code>grmc</code></td><td><code>git rm --cached</code></td><td>从索引中移除（保留在磁盘上）</td></tr><tr><td><code>gst</code></td><td><code>git status</code></td><td>显示工作树状态</td></tr><tr><td><code>gsts</code></td><td><code>git status --short</code></td><td>简短格式状态</td></tr><tr><td><code>gstsb</code></td><td><code>git status --short --branch</code></td><td>带分支信息的简短状态</td></tr><tr><td><code>gsta</code></td><td><code>git stash save</code></td><td>暂存当前更改</td></tr><tr><td><code>gstp</code></td><td><code>git stash pop</code></td><td>应用并移除最新暂存</td></tr><tr><td><code>gstd</code></td><td><code>git stash drop</code></td><td>删除最新暂存条目</td></tr><tr><td><code>gclout</code></td><td><code>git clean -df &amp;&amp; git checkout -- .</code></td><td>丢弃所有更改和未跟踪文件</td></tr></tbody></table><h2 id="提交" tabindex="-1">提交 <a class="header-anchor" href="#提交" aria-label="Permalink to &quot;提交&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>gc</code></td><td><code>git commit -a</code></td><td>提交所有已跟踪的更改</td></tr><tr><td><code>gca</code></td><td><code>git commit --amend</code></td><td>修改上次提交</td></tr><tr><td><code>gcall</code></td><td><code>git add -A &amp;&amp; git commit -av</code></td><td>暂存所有内容并详细提交</td></tr><tr><td><code>gcam</code></td><td><code>git commit --amend --message</code></td><td>使用新消息修改提交</td></tr><tr><td><code>gcane</code></td><td><code>git commit --amend --no-edit</code></td><td>修改提交但不更改消息</td></tr><tr><td><code>gcm</code></td><td><code>git commit --message</code></td><td>使用内联消息提交</td></tr></tbody></table><h2 id="差异和历史" tabindex="-1">差异和历史 <a class="header-anchor" href="#差异和历史" aria-label="Permalink to &quot;差异和历史&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>gd</code></td><td><code>git diff</code></td><td>显示未暂存的更改</td></tr><tr><td><code>gdch</code></td><td><code>git diff --name-status</code></td><td>显示已更改文件的名称和状态</td></tr><tr><td><code>gdh</code></td><td><code>git diff HEAD</code></td><td>显示自上次提交以来的所有更改</td></tr><tr><td><code>gdstaged</code></td><td><code>git diff --staged</code></td><td>显示已暂存的更改</td></tr><tr><td><code>gdcached</code></td><td><code>git diff --cached</code></td><td>显示索引和 HEAD 之间的更改</td></tr><tr><td><code>gdstat</code></td><td><code>git diff --stat --ignore-space-change -r</code></td><td>生成忽略空白的差异统计</td></tr><tr><td><code>gl</code></td><td><code>git log --since=&quot;last month&quot; --oneline</code></td><td>上个月的单行日志</td></tr><tr><td><code>glg</code></td><td><code>git log --graph --all --oneline --decorate</code></td><td>所有分支的图形日志</td></tr><tr><td><code>glgg</code></td><td><code>git log --oneline --graph --full-history --all --color --decorate</code></td><td>带颜色的完整历史图形日志</td></tr><tr><td><code>glc</code></td><td><code>git log --oneline --reverse</code></td><td>按时间顺序的单行日志</td></tr><tr><td><code>gld</code></td><td><code>git log --since=1-day-ago</code></td><td>最近 24 小时的日志</td></tr><tr><td><code>gldc</code></td><td><code>git log -1 --date-order --format=%cI</code></td><td>最新提交的 ISO 8601 日期</td></tr><tr><td><code>gldl</code></td><td><code>git log --date=local</code></td><td>使用本地时区的日志</td></tr><tr><td><code>glf</code></td><td><code>git log ORIG_HEAD.. --stat --no-merges</code></td><td>fetch 后的新提交（不含合并）</td></tr><tr><td><code>gll</code></td><td><em>(装饰图形格式)</em></td><td>带作者和 GPG 状态的详细图形日志</td></tr></tbody></table><h2 id="分支" tabindex="-1">分支 <a class="header-anchor" href="#分支" aria-label="Permalink to &quot;分支&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>gb</code></td><td><code>git branch</code></td><td>列出本地分支</td></tr><tr><td><code>gbd</code></td><td><code>git branch -d</code></td><td>删除已合并的分支</td></tr><tr><td><code>gbl</code></td><td><code>git branch -l</code></td><td>按模式列出分支</td></tr><tr><td><code>gbr</code></td><td><code>git branch -r</code></td><td>列出远程分支</td></tr><tr><td><code>gbrd</code></td><td><code>git branch -d -r</code></td><td>删除远程跟踪分支</td></tr><tr><td><code>gbrsb</code></td><td><code>git show-branch</code></td><td>显示分支及其提交</td></tr><tr><td><code>gswb</code></td><td><code>git switch</code></td><td>切换分支（现代方式）</td></tr><tr><td><code>gcode</code></td><td><code>git checkout main &amp;&amp; git branch --merged | xargs git branch --delete</code></td><td>删除所有已合并到 main 的分支</td></tr><tr><td><code>gcom</code></td><td><code>git checkout main &amp;&amp; git fetch origin --prune &amp;&amp; git reset --hard origin/main</code></td><td>将本地 main 重置为远程</td></tr></tbody></table><h2 id="远程和推送-拉取" tabindex="-1">远程和推送/拉取 <a class="header-anchor" href="#远程和推送-拉取" aria-label="Permalink to &quot;远程和推送/拉取&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>gf</code></td><td><code>git fetch</code></td><td>从远程获取</td></tr><tr><td><code>gp</code></td><td><code>git pull</code></td><td>从远程拉取</td></tr><tr><td><code>gph</code></td><td><code>git push</code></td><td>推送到远程</td></tr><tr><td><code>gpo</code></td><td><code>git push origin</code></td><td>推送到 origin</td></tr><tr><td><code>gpb</code></td><td><code>git push --set-upstream origin $(git branch --show-current)</code></td><td>推送并为当前分支设置 upstream</td></tr><tr><td><code>gpoll</code></td><td><code>git push origin --all</code></td><td>将所有分支推送到 origin</td></tr><tr><td><code>gpull</code></td><td><code>git pull</code></td><td>从远程拉取</td></tr><tr><td><code>gpush</code></td><td><code>git push</code></td><td>推送到远程</td></tr><tr><td><code>gr</code></td><td><code>git remote</code></td><td>管理远程仓库</td></tr><tr><td><code>gra</code></td><td><code>git remote add</code></td><td>添加新远程</td></tr><tr><td><code>grall</code></td><td><code>git remote | xargs -L1 git push --all</code></td><td>将所有分支推送到所有远程</td></tr><tr><td><code>grao</code></td><td><code>git remote add origin</code></td><td>添加 origin 远程</td></tr><tr><td><code>grv</code></td><td><code>git remote -v</code></td><td>显示远程 URL</td></tr></tbody></table><h2 id="撤销和重置" tabindex="-1">撤销和重置 <a class="header-anchor" href="#撤销和重置" aria-label="Permalink to &quot;撤销和重置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>grev</code></td><td><code>git revert</code></td><td>撤销一个提交</td></tr><tr><td><code>grevnc</code></td><td><code>git revert --no-commit</code></td><td>撤销但不自动提交</td></tr><tr><td><code>grb</code></td><td><code>git rebase</code></td><td>变基当前分支</td></tr><tr><td><code>grbk</code></td><td><code>git reset --soft HEAD^</code></td><td>撤销上次提交，保持更改已暂存</td></tr><tr><td><code>grescl</code></td><td><code>git reset --hard HEAD~1 &amp;&amp; git clean -fd</code></td><td>硬重置并清理未跟踪文件</td></tr><tr><td><code>gresh</code></td><td><code>git reset --hard HEAD~1</code></td><td>硬重置到上一个提交</td></tr><tr><td><code>gresp</code></td><td><code>git reset --hard &amp;&amp; git clean -ffdx</code></td><td>将所有内容重置为初始状态</td></tr><tr><td><code>gress</code></td><td><code>git reset --soft HEAD~1</code></td><td>软重置（保持更改已暂存）</td></tr></tbody></table><h2 id="子模块" tabindex="-1">子模块 <a class="header-anchor" href="#子模块" aria-label="Permalink to &quot;子模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>gsm</code></td><td><code>git submodule</code></td><td>管理子模块</td></tr><tr><td><code>gsmi</code></td><td><code>git submodule init</code></td><td>初始化子模块</td></tr><tr><td><code>gsma</code></td><td><code>git submodule add</code></td><td>添加子模块</td></tr><tr><td><code>gsms</code></td><td><code>git submodule sync</code></td><td>将子模块 URL 与 .gitmodules 同步</td></tr><tr><td><code>gsmu</code></td><td><code>git submodule update</code></td><td>更新子模块</td></tr><tr><td><code>gsmui</code></td><td><code>git submodule update --init</code></td><td>更新并初始化子模块</td></tr><tr><td><code>gsmuir</code></td><td><code>git submodule update --init --recursive</code></td><td>更新、初始化并递归子模块</td></tr></tbody></table><h2 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>gg</code></td><td><code>git grep</code></td><td>搜索仓库内容</td></tr><tr><td><code>gbs</code></td><td><code>git bisect</code></td><td>二分查找引入 bug 的提交</td></tr><tr><td><code>undopush</code></td><td><code>git push -f origin HEAD^:master</code></td><td>强制撤销上次推送到 master</td></tr></tbody></table><h2 id="签名和安全" tabindex="-1">签名和安全 <a class="header-anchor" href="#签名和安全" aria-label="Permalink to &quot;签名和安全&quot;">​</a></h2><table tabindex="0"><thead><tr><th>别名</th><th>命令</th><th>描述</th></tr></thead><tbody><tr><td><code>enable-signing</code></td><td><em>(交互式向导)</em></td><td>配置 GPG 或 SSH 提交签名</td></tr><tr><td><code>verify-signatures</code></td><td><code>git log --show-signature -n 10</code></td><td>验证最近 10 次提交的签名</td></tr><tr><td><code>check-signing</code></td><td><code>git config --list | grep &quot;gpg|signing&quot;</code></td><td>检查当前签名配置</td></tr></tbody></table>',23)])])}const b=d(r,[["render",a]]);export{m as __pageData,b as default};
